using namespace std;

int main()
{
    pair<string, int> student = {"Aman", 20};

    cout << student.first << " is " << student.second << " years old." << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <utility>
#include <string>

using namespace std;

int main()
{
    vector<pair<string, int>> students;
    students.push_back({"Aman", 20});
    students.push_back({"Priya", 22});

    for (int i = 0; i < students.size(); i++)
    {
        cout << students[i].first << ": " << students[i].second << endl;
    }

    return 0;
}

